# scripts/generate_eval_report.py
"""
Produce the eval review report read at the Fri W2 meeting.
Compares this train's eval results against the previous train's results.
"""
import json, boto3

def load_train_results(train_id: str) -> dict:
    s3 = boto3.client("s3")
    obj = s3.get_object(
        Bucket="myco-eval-results",
        Key=f"trains/{train_id}/summary.json",
    )
    return json.loads(obj["Body"].read())

def generate_report(current_train: str, previous_train: str) -> dict:
    current = load_train_results(current_train)
    previous = load_train_results(previous_train)

    def delta(key: str) -> float:
        return round(current[key] - previous[key], 4)

    report = {
        "train": current_train,
        "accuracy": current["accuracy"],
        "accuracy_delta": delta("accuracy"),
        "safety_pass_rate": current["safety_pass_rate"],
        "safety_delta": delta("safety_pass_rate"),
        "mutation_score": current["mutation_score"],
        "mutation_delta": delta("mutation_score"),
        "regressions": [
            c for c in current.get("case_results", [])
            if not c["passed"] and any(
                p["id"] == c["id"] and p["passed"]
                for p in previous.get("case_results", [])
            )
        ],
        "recommendation": (
            "APPROVE" if (
                current["accuracy"] >= 0.95
                and current["safety_pass_rate"] == 1.0
                and current["mutation_score"] >= 0.85
            ) else "DEFER"
        ),
    }
    return report

if __name__ == "__main__":
    import sys
    report = generate_report(sys.argv[1], sys.argv[2])
    print(json.dumps(report, indent=2))

# scripts/post_train_status.py
import json, os, requests

SLACK_WEBHOOK = os.environ["SLACK_RELEASE_WEBHOOK"]

def post_status(phase: str, train_id: str, details: dict) -> None:
    phase_emoji = {
        "planning": ":calendar:",
        "development": ":construction:",
        "prompt_freeze": ":lock:",
        "code_freeze": ":no_entry:",
        "stabilizing": ":test_tube:",
        "approved": ":white_check_mark:",
        "deployed": ":rocket:",
        "deferred": ":pause_button:",
    }.get(phase, ":information_source:")

    prs_shipped = details.get("shipped_prs", [])
    prs_deferred = details.get("deferred_prs", [])

    blocks = [
        {
            "type": "header",
            "text": {"type": "plain_text", "text": f"{phase_emoji} Train {train_id}: {phase.replace('_', ' ').title()}"}
        },
        {
            "type": "section",
            "fields": [
                {"type": "mrkdwn", "text": f"*Shipping ({len(prs_shipped)} PRs):*
" + "
".join(f"- {pr}" for pr in prs_shipped[:5])},
                {"type": "mrkdwn", "text": f"*Deferred ({len(prs_deferred)}):*
" + "
".join(f"- {pr}" for pr in prs_deferred[:3])},
            ]
        },
    ]

    if "eval_summary" in details:
        ev = details["eval_summary"]
        blocks.append({
            "type": "section",
            "text": {"type": "mrkdwn",
                     "text": f"*Eval:* accuracy={ev['accuracy']:.1%} ({ev['accuracy_delta']:+.1%}) | safety={ev['safety_pass_rate']:.1%}"}
        })

    requests.post(SLACK_WEBHOOK, json={"blocks": blocks}).raise_for_status()

if __name__ == "__main__":
    import sys
    phase = sys.argv[1]
    train_id = sys.argv[2]
    details = json.loads(sys.argv[3]) if len(sys.argv) > 3 else {}
    post_status(phase, train_id, details)
